  9→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
 10→import theme from '@semparar/design-system-app/src/styles/theme';
 11→import React, { FC, RefObject } from 'react';
 12→import { FlatList, RefreshControl } from 'react-native';
 13→import ApiError from '../../atomic/organisms/ApiError';
 14→import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
 15→import BasicScreen from '../../atomic/templates/BasicScreen';
 16→import { MyOrdersItemPropsView, STATUS_COLORS } from './models';
 17→
 18→const MyOrdersRewardProgramView: FC<MyOrdersItemPropsView> = ({
 19→  handleGoBack,
 20→  myOrders,
 21→  emptyImage,
 22→  formatDate,
 23→  isLoading,
 24→  isError,
 25→  modalizeRefFilters,
 26→  handleOpenFilters,
 27→  handleDetailsOrders,
 28→  handleRefresh,
 29→  filterGroups,
 30→  isRefreshing,
