  1→import {
  2→  NavigationProp,
  3→  useFocusEffect,
  4→  useNavigation,
  5→} from '@react-navigation/native';
  6→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  7→import { format, parseISO } from 'date-fns';
  8→import React, { useCallback, useMemo, useRef, useState } from 'react';
  9→import { Dimensions } from 'react-native';
 10→import { PropsRootStack } from 'src/routes/Models';
 11→import { useShallow } from 'zustand/react/shallow';
 12→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
 13→import { useRootStore } from '~/store';
 14→import { PERIOD_DAYS_MAP, PointsExtractStatus } from '../../services/models';
 15→import { getPointsExtract } from '../../services/services';
 16→import { FilterGroup } from '../ExtractRewardProgram/Models';
 17→import { getFilteredTransactions } from '../ExtractRewardProgram/utils';
 18→import MyOrdersRewardProgramView from './view';
 19→
 20→const PERIOD_FILTERS = [
 21→  {
 22→    label: '7 dias',
 23→    value: 0,
 24→  },
 25→  {
 26→    label: '15 dias',
 27→    value: 1,
 28→  },
 29→  {
 30→    label: '30 dias',
 31→    value: 2,
 32→  },
 33→  {
 34→    label: '60 dias',
 35→    value: 3,
 36→  },
 37→  {
 38→    label: '90 dias',
 39→    value: 4,
 40→  },
 41→];
 42→
 43→const TYPE_FILTERS = [
 44→  {
 45→    label: 'Mais recentes',
 46→    value: 'ASC',
 47→  },
 48→  {
 49→    label: 'Mais antigas',
 50→    value: 'DESC',
 51→  },
 52→];
 53→
 54→const MyOrdersRewardProgram = () => {
 55→  const [isRefreshing, setIsRefreshing] = useState(false);
 56→
 57→  const modalizeRefFilters = useRef<PropsModalizeRef>(null);
 58→  const emptyImage =
 59→    'https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png';
 60→
 61→  const SKELETON_COUNT = 3;
 62→  const { width } = Dimensions.get('window');
 63→
 64→  const { pointsExtract, pointsExtractFilters, pointsExtractActions } =
 65→    useRootStore(
 66→      useShallow(state => ({
 67→        pointsExtract: state.pointsExtract,
 68→        pointsExtractFilters: state.pointsExtractFilters,
 69→        pointsExtractActions: state.pointsExtractActions,
 70→      })),
 71→    );
 72→
 73→  const appliedTransactionsFilters =
 74→    pointsExtractFilters.appliedTransactionsFilters;
 75→
 76→  const getFormatDate = (iso?: string) => {
 77→    if (!iso) return '';
 78→    const date = parseISO(iso);
 79→    return format(date, 'dd/MM/yyyy');
 80→  };
 81→
 82→  const getFilterGroups: FilterGroup[] = useMemo(() => {
 83→    return [
 84→      {
 85→        label: 'Períodos',
 86→        options: PERIOD_FILTERS,
 87→      },
 88→      {
 89→        label: 'Relevância',
 90→        options: TYPE_FILTERS,
 91→      },
 92→    ];
 93→  }, []);
 94→
 95→  const handleApplyFilters = useCallback(
 96→    (filters: Record<number, unknown>) => {
 97→      const period = filters[0] as number | undefined;
 98→      const order = filters[1] as string | undefined;
 99→
100→      const hasPeriod = period !== undefined && period !== null;
101→      const hasOrdering = order !== undefined && order !== null;
102→
103→      const parts: string[] = ['filtrar'];
104→
105→      if (hasPeriod) {
106→        const periodDay = PERIOD_FILTERS[period].label.split(' ')[0];
107→        parts.push(`${periodDay}_dias`);
108→      }
109→
110→      if (hasOrdering) {
111→        const label = TYPE_FILTERS.find(item => item.value === order)?.label;
112→        if (label) {
113→          parts.push(label === 'Mais recentes' ? 'recentes' : 'antigas');
114→        }
115→      }
116→
117→      eventSelectContent({
118→        content_type: 'cta',
119→        content_id: parts.join('_'),
120→        location_1: 'monetizacao',
121→        location_2: 'hub_recompensas_spmais',
122→        location_3: 'meus_pedidos',
123→      });
124→
125→      pointsExtractActions.setTransactionsFilters({
126→        period: hasPeriod
127→          ? PERIOD_DAYS_MAP[period as keyof typeof PERIOD_DAYS_MAP]
128→          : undefined,
129→        order: hasOrdering ? (order as 'ASC' | 'DESC') : undefined,
130→      });
131→    },
132→    [pointsExtractActions],
133→  );
134→
135→  const getActiveFiltersCount = useCallback(() => {
136→    let count = 0;
137→    if (appliedTransactionsFilters?.period) count++;
138→    if (appliedTransactionsFilters?.order) count++;
139→    return count;
140→  }, [appliedTransactionsFilters]);
141→
142→  const getInitialFilters = useMemo(() => {
143→    const initial: Record<number, unknown> = {};
144→
145→    if (appliedTransactionsFilters?.period) {
146→      const periodIndex = Object.entries(PERIOD_DAYS_MAP).find(
147→        ([, days]) => days === appliedTransactionsFilters.period,
148→      )?.[0];
149→      if (periodIndex !== undefined) {
150→        initial[0] = Number(periodIndex);
151→      }
152→    }
153→
154→    if (appliedTransactionsFilters?.order) {
155→      initial[1] = appliedTransactionsFilters.order;
156→    }
157→
158→    return initial;
159→  }, [appliedTransactionsFilters]);
160→
161→  const handleOpenFilters = () => {
162→    eventSelectContent({
163→      content_type: 'cta',
164→      content_id: 'filtro_pedidos',
165→      location_1: 'monetizacao',
166→      location_2: 'hub_recompensas_spmais',
167→      location_3: 'meus_pedidos',
168→    });
169→
170→    modalizeRefFilters.current?.open?.();
171→  };
172→
173→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
174→
175→  const handleDetailsOrders = (
176→    transactionId: string,
177→    type?: string,
178→    icon?: string,
179→    status?: string,
180→    origination?: string
181→  )=> {
182→    eventSelectContent({
183→      content_type: 'cta',
184→      content_id: 'detalhe_pedido',
185→      location_1: 'monetizacao',
186→      location_2: 'hub_recompensas_spmais',
187→      location_3: 'meus_pedidos',
188→    });
189→
190→    navigation.navigate('MyOrdersDetails', {
191→      transactionId,
192→      type,
193→      icon,
194→      status,
195→      origination,
196→      analytics: {
197→        screen_name: 'detalhe_pedido',
198→        screen_class: 'hub_recompensas_spmais',
199→        screen_bussines: 'monetizacao',
200→        screen_info: {
201→          location_1: 'monetizacao',
202→          location_2: 'hub_recompensas_spmais',
203→          location_3: 'detalhe_pedido',
204→        },
205→      },
206→    });
207→  };
208→
209→  const myOrders = useMemo(() => {
210→    const allOrders = pointsExtract?.extractData?.transactions || [];
211→    return getFilteredTransactions(allOrders, appliedTransactionsFilters);
212→  }, [
213→    pointsExtract?.extractData?.transactions,
214→    appliedTransactionsFilters,
215→  ]);
216→
217→  const isLoading = pointsExtract.status === PointsExtractStatus.LOADING;
218→  const isError = pointsExtract.status === PointsExtractStatus.ERROR;
219→
220→  const handleGoBack = () => {
221→    pointsExtractActions.clearTransactionsFilters();
222→    pointsExtractActions.reset();
223→    navigation.goBack();
224→  };
225→
226→  const handleRefresh = async () => {
227→    setIsRefreshing(true);
228→    await getPointsExtract({ type: 'Resgate' });
229→    setIsRefreshing(false);
230→  };
231→
232→  const hasFocused = useRef(false);
233→  useFocusEffect(
234→    React.useCallback(() => {
235→      if (!hasFocused.current) {
236→        eventScreenViewV3(
237→          'meus_pedidos',
238→          'hub_recompensas_spmais',
239→          'monetizacao',
240→          {
241→            location_1: 'monetizacao',
242→            location_2: 'hub_recompensas_spmais',
243→            location_3: 'meus_pedidos',
244→          },
245→        );
246→        pointsExtractActions.clearTransactionsFilters();
247→        pointsExtractActions.reset();
248→        getPointsExtract({ type: 'Resgate' });
249→        hasFocused.current = true;
250→      }
251→      return () => {
252→        hasFocused.current = false;
253→      };
254→    }, [pointsExtractActions]),
255→  );
256→
257→  return (
258→    <MyOrdersRewardProgramView
259→      myOrders={myOrders}
260→      emptyImage={emptyImage}
261→      isLoading={isLoading}
262→      isError={isError}
263→      filterGroups={getFilterGroups}
264→      modalizeRefFilters={modalizeRefFilters}
265→      formatDate={getFormatDate}
266→      handleGoBack={handleGoBack}
267→      handleOpenFilters={handleOpenFilters}
268→      handleDetailsOrders={handleDetailsOrders}
269→      isRefreshing={isRefreshing}
270→      handleRefresh={handleRefresh}
271→      skeletonCount={SKELETON_COUNT}
272→      screenWidth={width}
273→      handleApplyFilters={handleApplyFilters}
274→      initialFilters={getInitialFilters}
275→      activeFiltersCount={getActiveFiltersCount()}
276→    />
277→  );
278→};
279→
280→export default MyOrdersRewardProgram;
